import{_ as a,o as e,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"What is Tracium?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-tracium.md","filePath":"guide/what-is-tracium.md"}'),n={name:"guide/what-is-tracium.md"};function r(l,t,o,d,h,p){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="what-is-tracium" tabindex="-1">What is Tracium? <a class="header-anchor" href="#what-is-tracium" aria-label="Permalink to &quot;What is Tracium?&quot;">​</a></h1><p>Tracium is <strong>execution intelligence infrastructure</strong>. It captures program execution — every variable assignment, every method call, every heap mutation — and turns it into structured, persistent, queryable data.</p><blockquote><p><strong>Tracium is to execution what Kafka is to events.</strong> Kafka made events durable and replayable. Tracium makes execution durable and replayable.</p></blockquote><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>When you run a program today, execution is invisible. Variables change, methods are called, objects are created — but once the program finishes, all that state is gone.</p><p>You&#39;re left with:</p><ul><li><strong>Logs</strong> — partial, human-written, lossy</li><li><strong>Metrics</strong> — aggregated, no state detail</li><li><strong>Debugger memory</strong> — ephemeral, gone when you close it</li><li><strong>Stack traces</strong> — only on errors, only the crash point</li></ul><p>No system answers: <em>&quot;What EXACTLY was the state of the program at every step, and can I replay it?&quot;</em></p><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>Tracium captures execution at the state level:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Code → Execution → State Timeline → Persistent, Queryable, Replayable Data</span></span></code></pre></div><p>Every execution produces a <strong>UEF trace</strong> — a structured document containing:</p><ul><li><strong>Stack frames</strong> with local variables and parameters at every step</li><li><strong>Heap objects</strong> with fields, elements, and reference relationships</li><li><strong>State deltas</strong> showing what changed (before/after values)</li><li><strong>Event classification</strong> (VARIABLE_ASSIGNED, OBJECT_ALLOCATED, FIELD_UPDATED, etc.)</li><li><strong>Source anchors</strong> linking every state change back to source code</li></ul><h2 id="what-it-looks-like" tabindex="-1">What It Looks Like <a class="header-anchor" href="#what-it-looks-like" aria-label="Permalink to &quot;What It Looks Like&quot;">​</a></h2><p>Submit Java code to Tracium:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">args</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> z </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> y;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Get back a step-by-step trace:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 3: LINE_CHANGED    line 3  | locals: {}</span></span>
<span class="line"><span>Step 4: VARIABLE_ASSIGNED line 4  | x = 5        [delta: x: null → 5]</span></span>
<span class="line"><span>Step 5: VARIABLE_ASSIGNED line 5  | x = 5, y = 10 [delta: y: null → 10]</span></span>
<span class="line"><span>Step 6: VARIABLE_ASSIGNED line 6  | x = 5, y = 10, z = 15 [delta: z: null → 15]</span></span></code></pre></div><p>Every variable, every assignment, every step — captured from real JVM execution via JDI.</p><h2 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td><strong>Sandbox Execution</strong></td><td>Compile and run Java code in a controlled environment</td></tr><tr><td><strong>Full State Capture</strong></td><td>Stack frames, heap objects, references at every step</td></tr><tr><td><strong>Variable Deltas</strong></td><td>Before/after values for every mutation</td></tr><tr><td><strong>Event Classification</strong></td><td>VARIABLE_ASSIGNED, OBJECT_ALLOCATED, FIELD_UPDATED, etc.</td></tr><tr><td><strong>Persistent Traces</strong></td><td>Stored on disk, queryable by filter, replayable anytime</td></tr><tr><td><strong>REST API</strong></td><td>Submit code, retrieve traces, query history</td></tr><tr><td><strong>Multi-Consumer</strong></td><td>Visualization, SDK, IDE plugin, AI — all consume UEF</td></tr></tbody></table><h2 id="how-it-s-different" tabindex="-1">How It&#39;s Different <a class="header-anchor" href="#how-it-s-different" aria-label="Permalink to &quot;How It&#39;s Different&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Debuggers</th><th>Observability</th><th>Visualizers</th><th><strong>Tracium</strong></th></tr></thead><tbody><tr><td><strong>State capture</strong></td><td>Real-time only</td><td>Metrics only</td><td>Toy snippets</td><td>Full state, persisted</td></tr><tr><td><strong>Persistence</strong></td><td>Ephemeral</td><td>Time-series</td><td>Ephemeral</td><td>Durable artifacts</td></tr><tr><td><strong>Queryable</strong></td><td>No</td><td>Metric queries</td><td>No</td><td>Filter, search, compare</td></tr><tr><td><strong>Production</strong></td><td>Not intended</td><td>Yes (shallow)</td><td>No</td><td>Attach mode</td></tr><tr><td><strong>AI-friendly</strong></td><td>No</td><td>Limited</td><td>No</td><td>Structured, segmentable</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/why-tracium.html">Why Tracium?</a> — The paradigm shift in detail</li><li><a href="/guide/getting-started.html">Getting Started</a> — Run your first trace in 2 minutes</li><li><a href="/guide/execution-as-data.html">Core Concepts</a> — Understand execution as data</li></ul>`,25)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
